#include<bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e3 + 7;
int dp[N],vis[N];
int n;
int bfs(int n){
	int cnt = 0;
	queue<int> q;
	q.push(n);
	while(!q.empty()){
		cnt++;
		int x = q.front();
		q.pop();
		for(int i = 1; i <= x / 2; i++){
			q.push(i);							 
		}
	}
	return cnt;
}
signed main(){

	cin >> n;
//	memset(dp,1,sizeof(dp));
	dp[1] = 1;
	for(int i = 2; i <= n; i++){
		for(int j = 1; j <= i / 2; j++){
			dp[i] += dp[j];
		}
		dp[i] += 1;
		//cout << dp[i] << ' ';
	}
	cout << dp[n];
}
